import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, User, Edit } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

// 1. MUST use "export const AdminArtists" (Named Export)
export const AdminArtists = () => {
  const [artists, setArtists] = useState<any[]>([]);

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllArtists();
      setArtists(Array.isArray(res.data) ? res.data : []);
    } catch (err) {
      toast.error("Artists Sync Failed");
      setArtists([]);
    }
  };

  useEffect(() => { fetchData(); }, []);

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase tracking-tighter italic">Archive <span className="text-primary">Artists</span></h1>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-widest mt-1">Personnel Registry</p>
        </div>
        <Link to="/admin/artists/add" className="bg-black text-white px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-all shadow-xl">
          <Plus size={16} /> Register Artist
        </Link>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {artists.map((artist: any) => (
          <div key={artist._id} className="bg-white dark:bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-gray-100 dark:border-white/5 group shadow-sm">
            <div className="flex items-center gap-6 mb-6">
              <div className="w-16 h-16 bg-gray-100 dark:bg-white/5 rounded-2xl flex items-center justify-center overflow-hidden">
                {artist.Image ? (
                  <img src={artist.Image} className="w-full h-full object-cover" alt="" />
                ) : (
                  <User size={24} className="text-gray-300" />
                )}
              </div>
              <div>
                <h4 className="font-black uppercase text-xs italic">{artist.Name_En}</h4>
                <p className="text-[10px] font-bold text-primary uppercase">{artist.Artist_ID}</p>
              </div>
            </div>
            <div className="flex gap-2">
              {/* This link triggers the "edit/:id" route in App.tsx */}
              <Link to={`/admin/artists/edit/${artist.Artist_ID}`} className="flex-1 py-3 bg-gray-50 dark:bg-white/5 rounded-xl font-black text-[9px] uppercase text-center hover:bg-black hover:text-white transition-all flex items-center justify-center gap-2">
                <Edit size={12}/> Profile
              </Link>
              <button className="px-4 py-3 bg-red-50 text-red-500 rounded-xl hover:bg-red-500 hover:text-white transition-all">
                <Trash2 size={14}/>
              </button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
